use serde::{Deserialize, Serialize};

pub const SEMANTIC_AUTHORITY_BOUNDARY_THEOREM: &str =
    "Gnosis.SemanticAuthorityBoundary.no_unwitnessed_semantic_authority";

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum SharedUiEvidenceSurface {
    EmotionTaxonomyValidation,
    IntentSignal,
    SpeakerIdentification,
    MentalHealthLayer,
    CulturalEnvironmentLayer,
    AuthorityDelta,
    ToolObservation,
    UserCorrection,
    ExternalRecord,
    ClinicalAttestation,
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum SemanticClaimKind {
    AffectLabel,
    SpeakerIdentity,
    SpeakerIntent,
    DiagnosisHypothesis,
    CulturalFrame,
    AuthorityDelta,
    SemanticAuthority,
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum SemanticAuthorityVerdict {
    ObservationOnly,
    Candidate,
    SelfReported,
    ExternallyValidated,
    ClinicallyAttested,
    AuthorityBlocked,
    SemanticAuthorityGranted,
}

impl SemanticAuthorityVerdict {
    pub fn authority_granted(self) -> bool {
        matches!(self, Self::SemanticAuthorityGranted)
    }

    pub fn needs_obligation(self) -> bool {
        matches!(
            self,
            Self::ObservationOnly | Self::Candidate | Self::AuthorityBlocked
        )
    }
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct SemanticAuthorityClaimSpec {
    pub kind: SemanticClaimKind,
    pub label: String,
    #[serde(default)]
    pub evidence_surfaces: Vec<SharedUiEvidenceSurface>,
    #[serde(default)]
    pub confidence_milli: u32,
    #[serde(default)]
    pub evidence_mass: u32,
    #[serde(default)]
    pub self_reported: bool,
    #[serde(default)]
    pub user_confirmed: bool,
    #[serde(default)]
    pub externally_validated: bool,
    #[serde(default)]
    pub domain_credentialed: bool,
    #[serde(default)]
    pub contradiction_count: u32,
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct SemanticAuthorityClaimReport {
    pub kind: SemanticClaimKind,
    pub label: String,
    pub evidence_surfaces: Vec<SharedUiEvidenceSurface>,
    pub confidence_milli: u32,
    pub evidence_mass: u32,
    pub verdict: SemanticAuthorityVerdict,
    pub authority_granted: bool,
    pub obligation: Option<String>,
    pub observational_only: bool,
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct SemanticAuthorityBoundaryReport {
    pub theorem: String,
    pub claims: Vec<SemanticAuthorityClaimReport>,
    pub claim_count: u32,
    pub granted_count: u32,
    pub blocked_count: u32,
    pub provisional_count: u32,
    pub obligation_count: u32,
    pub observational_only: bool,
}

pub fn compile_semantic_authority_boundary(
    claims: Vec<SemanticAuthorityClaimSpec>,
) -> SemanticAuthorityBoundaryReport {
    let compiled = claims.into_iter().map(compile_claim).collect::<Vec<_>>();
    let claim_count = compiled.len() as u32;
    let granted_count = compiled
        .iter()
        .filter(|claim| claim.verdict.authority_granted())
        .count() as u32;
    let blocked_count = compiled
        .iter()
        .filter(|claim| claim.verdict == SemanticAuthorityVerdict::AuthorityBlocked)
        .count() as u32;
    let obligation_count = compiled
        .iter()
        .filter(|claim| claim.verdict.needs_obligation())
        .count() as u32;
    let provisional_count = claim_count.saturating_sub(granted_count);

    SemanticAuthorityBoundaryReport {
        theorem: SEMANTIC_AUTHORITY_BOUNDARY_THEOREM.to_string(),
        claims: compiled,
        claim_count,
        granted_count,
        blocked_count,
        provisional_count,
        obligation_count,
        observational_only: true,
    }
}

fn compile_claim(spec: SemanticAuthorityClaimSpec) -> SemanticAuthorityClaimReport {
    let verdict = semantic_authority_verdict(&spec);
    let authority_granted = verdict.authority_granted();
    let obligation = obligation_for(&spec, verdict);
    SemanticAuthorityClaimReport {
        kind: spec.kind,
        label: spec.label,
        evidence_surfaces: spec.evidence_surfaces,
        confidence_milli: spec.confidence_milli.min(1000),
        evidence_mass: spec.evidence_mass,
        verdict,
        authority_granted,
        obligation,
        observational_only: true,
    }
}

fn semantic_authority_verdict(spec: &SemanticAuthorityClaimSpec) -> SemanticAuthorityVerdict {
    if spec.contradiction_count > 0 {
        return SemanticAuthorityVerdict::AuthorityBlocked;
    }
    match spec.kind {
        SemanticClaimKind::DiagnosisHypothesis => {
            if spec.domain_credentialed && spec.externally_validated {
                SemanticAuthorityVerdict::ClinicallyAttested
            } else {
                SemanticAuthorityVerdict::Candidate
            }
        }
        SemanticClaimKind::CulturalFrame | SemanticClaimKind::SpeakerIntent => {
            if spec.self_reported && spec.user_confirmed {
                SemanticAuthorityVerdict::SelfReported
            } else {
                SemanticAuthorityVerdict::Candidate
            }
        }
        SemanticClaimKind::SpeakerIdentity => {
            if spec.externally_validated {
                SemanticAuthorityVerdict::ExternallyValidated
            } else {
                SemanticAuthorityVerdict::Candidate
            }
        }
        SemanticClaimKind::SemanticAuthority => {
            if spec.self_reported
                && spec.user_confirmed
                && spec.externally_validated
                && spec.domain_credentialed
            {
                SemanticAuthorityVerdict::SemanticAuthorityGranted
            } else {
                SemanticAuthorityVerdict::AuthorityBlocked
            }
        }
        SemanticClaimKind::AffectLabel => {
            if spec.externally_validated {
                SemanticAuthorityVerdict::ExternallyValidated
            } else {
                SemanticAuthorityVerdict::ObservationOnly
            }
        }
        SemanticClaimKind::AuthorityDelta => {
            if spec.self_reported && spec.user_confirmed {
                SemanticAuthorityVerdict::SelfReported
            } else {
                SemanticAuthorityVerdict::Candidate
            }
        }
    }
}

fn obligation_for(
    spec: &SemanticAuthorityClaimSpec,
    verdict: SemanticAuthorityVerdict,
) -> Option<String> {
    match verdict {
        SemanticAuthorityVerdict::ObservationOnly => Some(format!(
            "{} is observation-only; do not use it as speaker intent, diagnosis, culture, or semantic authority.",
            spec.label
        )),
        SemanticAuthorityVerdict::Candidate => Some(match spec.kind {
            SemanticClaimKind::SpeakerIntent => {
                format!("Confirm speaker intent for {} with self-report or explicit correction.", spec.label)
            }
            SemanticClaimKind::DiagnosisHypothesis => {
                format!("Keep {} as a non-clinical hypothesis unless clinically attested.", spec.label)
            }
            SemanticClaimKind::CulturalFrame => {
                format!("Ask for cultural self-description before treating {} as a cultural frame.", spec.label)
            }
            _ => format!("Argue or validate provisional semantic claim {}.", spec.label),
        }),
        SemanticAuthorityVerdict::AuthorityBlocked => Some(format!(
            "{} lacks required authority conditions or has contradictions.",
            spec.label
        )),
        _ => None,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn intent_diagnosis_and_culture_stay_provisional_without_authority() {
        let report = compile_semantic_authority_boundary(vec![
            SemanticAuthorityClaimSpec {
                kind: SemanticClaimKind::SpeakerIntent,
                label: "speaker wants to end".to_string(),
                evidence_surfaces: vec![SharedUiEvidenceSurface::IntentSignal],
                confidence_milli: 700,
                evidence_mass: 2,
                self_reported: false,
                user_confirmed: false,
                externally_validated: false,
                domain_credentialed: false,
                contradiction_count: 0,
            },
            SemanticAuthorityClaimSpec {
                kind: SemanticClaimKind::DiagnosisHypothesis,
                label: "anxiety".to_string(),
                evidence_surfaces: vec![SharedUiEvidenceSurface::MentalHealthLayer],
                confidence_milli: 640,
                evidence_mass: 3,
                self_reported: false,
                user_confirmed: false,
                externally_validated: false,
                domain_credentialed: false,
                contradiction_count: 0,
            },
            SemanticAuthorityClaimSpec {
                kind: SemanticClaimKind::CulturalFrame,
                label: "high-context communication".to_string(),
                evidence_surfaces: vec![SharedUiEvidenceSurface::CulturalEnvironmentLayer],
                confidence_milli: 500,
                evidence_mass: 1,
                self_reported: false,
                user_confirmed: false,
                externally_validated: false,
                domain_credentialed: false,
                contradiction_count: 0,
            },
        ]);

        assert_eq!(report.claim_count, 3);
        assert_eq!(report.granted_count, 0);
        assert_eq!(report.provisional_count, 3);
        assert_eq!(report.obligation_count, 3);
        assert!(report.observational_only);
        assert_eq!(
            report.claims[1].verdict,
            SemanticAuthorityVerdict::Candidate
        );
        assert!(report.claims[1]
            .obligation
            .as_deref()
            .unwrap_or_default()
            .contains("non-clinical hypothesis"));
    }

    #[test]
    fn semantic_authority_requires_all_conditions() {
        let report = compile_semantic_authority_boundary(vec![SemanticAuthorityClaimSpec {
            kind: SemanticClaimKind::SemanticAuthority,
            label: "signed correction".to_string(),
            evidence_surfaces: vec![
                SharedUiEvidenceSurface::UserCorrection,
                SharedUiEvidenceSurface::ExternalRecord,
            ],
            confidence_milli: 950,
            evidence_mass: 4,
            self_reported: true,
            user_confirmed: true,
            externally_validated: true,
            domain_credentialed: true,
            contradiction_count: 0,
        }]);

        assert_eq!(report.granted_count, 1);
        assert_eq!(
            report.claims[0].verdict,
            SemanticAuthorityVerdict::SemanticAuthorityGranted
        );
        assert!(report.claims[0].authority_granted);
    }
}
